import subprocess
import json

def convert_image(event, context):
    # Get filename and conversion options from event metadata
    filename = event['name']
    metadata = json.loads(event['metadata'])
    options = metadata.get('options', [])

    # Run convert command with event parameters
    subprocess.call(['convert', filename] + options)